const rows=$input.all().map(i=>i.json);
const ch=$('Trigger').first().json.channel, q=$('Trigger').first().json.qual_rate_pct;
const t=new Date().toISOString().slice(0,10);
const worst=rows.filter(r=>(r.qual_rate||0)<0.30).slice(0,5);

// Qual rate source: hubspot_leads_module_daily ONLY - NEVER platform conversion counts
// Qual rate = SUM(leads_qualified) / SUM(leads_total) from HubSpot CTE join
// #approvals required - this node outputs recommendation only, never auto-executes
// HubSpot READ-ONLY - any field/pipeline/stage changes require Rana/Amar sign-off via Slack

const worstLines = worst.map(r => {
  const pct = r.qual_rate != null ? (r.qual_rate*100).toFixed(1) : 'n/a';
  return `. ${r.campaign_name||'unknown'} - ${pct}% qual (${r.leads_total||0} leads, ${r.spend?'$'+r.spend.toFixed(0):'-'} spend)`;
}).join('\n');

return [{json:{
  task_name:`[URGENT - QUAL CRITICAL] ${ch} - Qual ${q}% below 30% threshold`,
  task_notes:`Channel: ${ch}
Qual Rate: ${q}% - CRITICAL (< 30% threshold)
Data source: hubspot_leads_module_daily (14-day window, CTE-joined to campaigns_daily)

ACTION REQUIRED (via #approvals - ? to execute, ? to skip):
? Redirect traffic to best same-category LP immediately
? Do NOT wait for a new LP - redirect existing best performer
? Budget cut or campaign pause requires #approvals ? first

Worst-performing campaigns (< 30% qual):
${worstLines}

CRO Handoff Chain:
? CRO Specialist creates LP brief
? UI/UX Designer reviews layout
? Developer implements changes
? Pixel verification: BOTH Meta pixels must fire on form submit + UTM passthrough confirmed on hidden fields
? LP sign-off ONLY after both conditions met

LinkedIn note: seniority/company-size filters map to utm_audience (Ad Set level).
Confirm UTM passthrough via HubSpot form fields before deploying any LinkedIn audience segment.

ESCALATE TO GROWTH-ANALYST for any HubSpot field changes, pipeline changes, or stage changes.
HubSpot is READ-ONLY without explicit Rana/Amar sign-off via Slack.

Created: ${t} | Due: TODAY | Priority: P0 | Type: LP Redirect | Channel: ${ch} | Asset level: Landing Page | Action: redirect ? [cro-specialist]`,
  due_on: t
}}];

