}).join('\n');

return [{json:{
  task_name:`[QUAL FIX] ${ch} - Qual rate ${q}% below 45% target`,
  task_notes:`Channel: ${ch}
Qual Rate: ${q}% - Below 45% target
Data source: hubspot_leads_module_daily (14-day window)
